// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.leo;

import java.util.Comparator;
import java.util.List;

import org.eclipse.rdf4j.common.annotation.Experimental;

/**
 * Shadow or applied ranking of Cascades plan alternatives from learned evidence.
 */
@Experimental
public record LeoPlanRanking(List<ScoredCandidate> candidates, boolean wouldChangeChoice, String reason) {

	public LeoPlanRanking {
		candidates = candidates == null ? List.of() : List.copyOf(candidates);
		reason = reason == null ? "" : reason;
	}

	public static LeoPlanRanking empty() {
		return new LeoPlanRanking(List.of(), false, "");
	}

	public static LeoPlanRanking byCost(List<LeoPlanCandidate> candidates, String reason) {
		if (candidates == null || candidates.isEmpty()) {
			return empty();
		}
		List<ScoredCandidate> scored = candidates.stream()
				.map(candidate -> new ScoredCandidate(candidate, candidate.costScore(), candidate.costScore(), 0.0d,
						"cost"))
				.sorted(Comparator.comparingDouble(ScoredCandidate::costScore))
				.toList();
		return new LeoPlanRanking(scored, false, reason == null ? "cost-order" : reason);
	}

	public ScoredCandidate bestCandidate() {
		return candidates.isEmpty() ? null : candidates.getFirst();
	}

	public String bestCandidateId() {
		ScoredCandidate best = bestCandidate();
		return best == null || best.candidate() == null ? "" : best.candidate().candidateId();
	}

	public String costWinnerCandidateId() {
		if (candidates.isEmpty()) {
			return "";
		}
		return candidates.stream()
				.min(Comparator.comparingDouble(ScoredCandidate::costScore))
				.map(scored -> scored.candidate() == null ? "" : scored.candidate().candidateId())
				.orElse("");
	}

	public double bestConfidence() {
		ScoredCandidate best = bestCandidate();
		return best == null ? 0.0d : best.confidence();
	}

	public String explainSummary() {
		if (candidates.isEmpty()) {
			return "";
		}
		ScoredCandidate best = bestCandidate();
		return "best=" + bestCandidateId()
				+ ", costWinner=" + costWinnerCandidateId()
				+ ", wouldChange=" + wouldChangeChoice
				+ ", learnedScore=" + best.learnedScore()
				+ ", costScore=" + best.costScore()
				+ ", confidence=" + best.confidence()
				+ ", source=" + best.source()
				+ ", reason=" + reason;
	}

	public record ScoredCandidate(LeoPlanCandidate candidate, double learnedScore, double costScore, double confidence,
			String source) {

		public ScoredCandidate {
			learnedScore = nonNegativeFiniteOrNaN(learnedScore);
			costScore = nonNegativeFiniteOrNaN(costScore);
			confidence = Double.isFinite(confidence) ? Math.max(0.0d, Math.min(1.0d, confidence)) : 0.0d;
			source = source == null ? "" : source;
		}

		private static double nonNegativeFiniteOrNaN(double value) {
			return Double.isFinite(value) && value >= 0.0d ? value : Double.NaN;
		}
	}
}
